-- AppSheet 在庫管理アプリ（Inventory Management Sheet.xlsx 管理表）からの移行データ
-- 生成スクリプト: scratchpad/gen_seed_sql.py（画像は移行対象外）











-- 登録者名を Workers マスタと突合して worker_id を設定（全角/半角空白を除去して比較）
UPDATE "InventoryItems" i
SET worker_id = w.id
FROM "Workers" w
WHERE i.worker_id IS NULL
  AND i.recorded_by IS NOT NULL
  AND replace(replace(w.name, ' ', ''), '　', '') = replace(replace(i.recorded_by, ' ', ''), '　', '');
